fn match_route<'a>(routes: &'a HashMap<&'static str, Route>, host: &str, path: &str) -> Option<&'a Route> {
    if host.starts_with("api.") || path.starts_with("/api/") {
        return routes.get("api");
    }
    if host.starts_with("static.") || path.starts_with("/static/") || path.starts_with("/assets/") {
        return routes.get("static");
    }
    if host.starts_with("legacy.") || path.starts_with("/legacy/") {
        return routes.get("legacy");
    }
    None
}

fn build_backend(route: &Route) -> Result<Backend, Error> {
    let mut b = Backend::builder(route.name, route.origin_host)
        .port(route.origin_port)
        .connect_timeout(std::time::Duration::from_secs(5))
        .first_byte_timeout(std::time::Duration::from_secs(30))
        .between_bytes_timeout(std::time::Duration::from_secs(30));

    if route.use_tls {
        b = b.use_ssl(true);

        if let Some(sni) = route.sni_hostname {
            b = b.ssl_sni_hostname(sni);
        }

        b = b.ssl_check_cert(route.verify_cert);
    } else {
        b = b.use_ssl(false);
    }

    b.finish()
}

fn sanitize_request(req: &mut Request, route: &Route, original_host: &str) {
    if req.get_method() == Method::CONNECT {
        *req = Request::new(Method::METHOD_NOT_ALLOWED, req.get_url());
        return;
    }

    req.remove_header(header::CONNECTION);
    req.remove_header(header::PROXY_CONNECTION);
    req.remove_header(header::KEEP_ALIVE);
    req.remove_header(header::TE);
    req.remove_header(header::TRANSFER_ENCODING);
    req.remove_header(header::UPGRADE);
    req.remove_header(header::FORWARDED);

    let client_ip = req
        .get_client_ip_addr()
        .map(|ip| ip.to_string())
        .unwrap_or_default();

    if !client_ip.is_empty() {
        append_xff(req, &client_ip);
        req.set_header("Fastly-Client-IP", client_ip);
    }

    req.set_header("X-Forwarded-Proto", if route.use_tls { "https" } else { "http" });
    req.set_header("X-Forwarded-Host", original_host);

    if let Some(h) = route.host_override {
        req.set_header(header::HOST, h);
    }
}

fn sanitize_response(resp: &mut Response) {
    resp.remove_header(header::CONNECTION);
    resp.remove_header(header::TRANSFER_ENCODING);
    resp.remove_header(header::SERVER);

    if resp.get_status() == StatusCode::SWITCHING_PROTOCOLS {
        resp.set_status(StatusCode::BAD_GATEWAY);
        resp.set_body_text_plain("Upgrades not supported");
    }
}

fn append_xff(req: &mut Request, ip: &str) {
    match req.get_header_str("X-Forwarded-For") {
        Some(existing) if !existing.trim().is_empty() => {
            let mut v = String::with_capacity(existing.len() + 2 + ip.len());
            v.push_str(existing);
            v.push_str(", ");
            v.push_str(ip);
            req.set_header("X-Forwarded-For", v);
        }
        _ => {
            req.set_header("X-Forwarded-For", ip);
        }
    }
}